1	package handler
2	
3	import (
4		"io"
5		"net/http"
6		"os"
7		"path/filepath"
8	
9		"github.com/google/uuid"
10		"github.com/labstack/echo/v4"
11		"github.com/ledgermint/platform/internal/dto"
12		"github.com/ledgermint/platform/internal/middleware"
13		"github.com/ledgermint/platform/internal/service"
14	)
15	
16	type MessageHandler struct {
17		messageService *service.MessageService
18		uploadDir      string
19	}
20	
21	func NewMessageHandler(ms *service.MessageService, uploadDir string) *MessageHandler {
22		return &MessageHandler{messageService: ms, uploadDir: uploadDir}
23	}
24	
25	func (h *MessageHandler) List(c echo.Context) error {
26		orderID, err := uuid.Parse(c.Param("orderId"))
27		if err != nil {
28			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
29		}
30	
31		userID, err := uuid.Parse(middleware.GetUserID(c))
32		if err != nil {
33			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
34		}
35	
36		page, pageSize := pagination(c)
37		messages, total, err := h.messageService.ListByOrder(c.Request().Context(), orderID, userID, page, pageSize)
38		if err != nil {
39			return mapError(c, err)
40		}
41		return paginatedResponse(c, messages, page, pageSize, total)
42	}
43	
44	func (h *MessageHandler) Send(c echo.Context) error {
45		orderID, err := uuid.Parse(c.Param("orderId"))
46		if err != nil {
47			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
48		}
49	
50		userID, err := uuid.Parse(middleware.GetUserID(c))
51		if err != nil {
52			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
53		}
54	
55		body := c.FormValue("body")
56		if body == "" {
57			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, "message body is required")
58		}
59	
60		// Server-side PII detection
61		if detected, piiTypes := service.DetectPII(body); detected {
62			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, service.PIIErrorMessage(piiTypes))
63		}
64	
65		var attachmentPath, attachmentMime string
66		var attachmentSize int
67	
68		file, err := c.FormFile("attachment")
69		if err == nil {
70			// Server-side 10MB enforcement
71			if file.Size > service.MaxAttachmentSize {
72				return errorResponse(c, http.StatusRequestEntityTooLarge, dto.CodeAttachmentTooLarge, "attachment exceeds 10MB limit")
73			}
74	
75			src, err := file.Open()
76			if err != nil {
77				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to read attachment")
78			}
79			defer src.Close()
80	
81			dir := filepath.Join(h.uploadDir, orderID.String())
82			if err := os.MkdirAll(dir, 0o755); err != nil {
83				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to create upload directory")
84			}
85	
86			ext := filepath.Ext(file.Filename)
87			filename := uuid.New().String() + ext
88			dstPath := filepath.Join(dir, filename)
89	
90			dst, err := os.Create(dstPath)
91			if err != nil {
92				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to save attachment")
93			}
94			defer dst.Close()
95	
96			if _, err := io.Copy(dst, src); err != nil {
97				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to write attachment")
98			}
99	
100			attachmentPath = dstPath
101			attachmentSize = int(file.Size)
102			attachmentMime = file.Header.Get("Content-Type")
103		}
104	
105		msg, err := h.messageService.Send(c.Request().Context(), orderID, userID, body,
106			attachmentPath, attachmentSize, attachmentMime)
107		if err != nil {
108			return mapError(c, err)
109		}
110		return c.JSON(http.StatusCreated, msg)
111	}
