1	import api from './client';
2	import type { Message, PaginatedResponse } from '../types';
3	
4	export const listMessages = (orderId: string, page = 1, pageSize = 50) =>
5	  api.get<PaginatedResponse<Message>>(`/orders/${orderId}/messages`, {
6	    params: { page, page_size: pageSize },
7	  });
8	
9	export const sendMessage = (orderId: string, body: string, attachment?: File) => {
10	  const formData = new FormData();
11	  formData.append('body', body);
12	  if (attachment) {
13	    formData.append('attachment', attachment);
14	  }
15	  return api.post<Message>(`/orders/${orderId}/messages`, formData, {
16	    headers: { 'Content-Type': 'multipart/form-data' },
17	  });
18	};
