1	import { useParams, Link } from 'react-router-dom';
2	import { useState, useRef, useEffect } from 'react';
3	import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
4	import { listMessages, sendMessage } from '../api/messages';
5	import { useAuthStore } from '../store/authStore';
6	import { detectPII } from '../utils/piiDetector';
7	import { formatRelativeTime } from '../utils/formatters';
8	
9	const MAX_ATTACHMENT_SIZE = 10 * 1024 * 1024;
10	
11	export function MessagesPage() {
12	  const { id: orderId } = useParams<{ id: string }>();
13	  const { user } = useAuthStore();
14	  const queryClient = useQueryClient();
15	  const [body, setBody] = useState('');
16	  const [attachment, setAttachment] = useState<File | null>(null);
17	  const [piiWarning, setPiiWarning] = useState('');
18	  const [fileError, setFileError] = useState('');
19	  const messagesEndRef = useRef<HTMLDivElement>(null);
20	
21	  const { data } = useQuery({
22	    queryKey: ['messages', orderId],
23	    queryFn: () => listMessages(orderId!, 1, 100).then((r) => r.data),
24	    enabled: !!orderId,
25	    refetchInterval: 10000,
26	  });
27	
28	  const [sendError, setSendError] = useState('');
29	
30	  const mutation = useMutation({
31	    mutationFn: () => sendMessage(orderId!, body, attachment || undefined),
32	    onSuccess: () => {
33	      setBody('');
34	      setAttachment(null);
35	      setPiiWarning('');
36	      setSendError('');
37	      queryClient.invalidateQueries({ queryKey: ['messages', orderId] });
38	    },
39	    onError: (err: any) => {
40	      const status = err.response?.status;
41	      const errorData = err.response?.data?.error;
42	      const code = errorData?.code;
43	      const message = errorData?.message;
44	
45	      if (status === 429 || code === 'ERR_RATE_LIMITED') {
46	        setSendError('Message blocked: You are sending messages too quickly. Please wait a moment before trying again.');
47	      } else if (status === 403 || code === 'ERR_FORBIDDEN') {
48	        setSendError('Message blocked: You are not authorized to send messages on this order. Only the buyer and seller can communicate.');
49	      } else if (status === 413 || code === 'ERR_ATTACHMENT_TOO_LARGE') {
50	        setSendError('Message blocked: The attachment exceeds the 10MB size limit. Please use a smaller file.');
51	      } else if (status === 422 || code === 'ERR_VALIDATION') {
52	        setSendError(`Message blocked: ${message || 'Invalid message content. Please check your input.'}`);
53	      } else {
54	        setSendError(message || 'Failed to send message. Please try again.');
55	      }
56	    },
57	  });
58	
59	  useEffect(() => {
60	    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
61	  }, [data]);
62	
63	  const handleSend = () => {
64	    const piiResult = detectPII(body);
65	    if (piiResult.detected) {
66	      setPiiWarning(`Message blocked: Your message contains sensitive personal information (${piiResult.types.join(', ')}). Please remove it before sending to protect privacy.`);
67	      return;
68	    }
69	    setPiiWarning('');
70	    setSendError('');
71	    mutation.mutate();
72	  };
73	
74	  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
75	    const file = e.target.files?.[0];
76	    setFileError('');
77	    if (file) {
78	      if (file.size > MAX_ATTACHMENT_SIZE) {
79	        setFileError('Attachment exceeds 10MB limit.');
80	        setAttachment(null);
81	        return;
82	      }
83	      setAttachment(file);
84	
85	      // Check text files for PII
86	      if (file.type.startsWith('text/') || file.name.endsWith('.csv') || file.name.endsWith('.txt')) {
87	        const reader = new FileReader();
88	        reader.onload = (ev) => {
89	          const content = ev.target?.result as string;
90	          const piiResult = detectPII(content);
91	          if (piiResult.detected) {
92	            setFileError(`Attachment contains sensitive content (${piiResult.types.join(', ')}). Remove PII before sending.`);
93	            setAttachment(null);
94	          }
95	        };
96	        reader.readAsText(file);
97	      }
98	    }
99	  };
100	
101	  return (
102	    <div className="max-w-3xl mx-auto">
103	      <Link to={`/orders/${orderId}`} className="text-sm text-primary-600 hover:underline mb-4 block">
104	        Back to Order
105	      </Link>
106	
107	      <div className="bg-white rounded-lg shadow-sm border flex flex-col h-[500px] md:h-[600px] lg:h-[700px]">
108	        <div className="p-4 border-b">
109	          <h2 className="font-semibold">Messages - Order #{orderId?.slice(0, 8)}</h2>
110	        </div>
111	
112	        <div className="flex-1 overflow-y-auto p-4 space-y-3">
113	          {data?.data?.map((msg) => {
114	            const isMe = msg.sender_id === user?.id;
115	            return (
116	              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
117	                <div className={`max-w-[70%] p-3 rounded-lg ${isMe ? 'bg-primary-100 text-primary-900' : 'bg-gray-100'}`}>
118	                  <p className="text-sm">{msg.body}</p>
119	                  {msg.attachment_path && (
120	                    <p className="text-xs mt-1 text-gray-500">
121	                      Attachment ({msg.attachment_mime}, {Math.round((msg.attachment_size || 0) / 1024)}KB)
122	                    </p>
123	                  )}
124	                  <p className="text-xs text-gray-400 mt-1">{formatRelativeTime(msg.created_at)}</p>
125	                </div>
126	              </div>
127	            );
128	          })}
129	          <div ref={messagesEndRef} />
130	        </div>
131	
132	        <div className="p-4 border-t">
133	          {piiWarning && (
134	            <div className="text-sm text-red-600 bg-red-50 p-3 rounded mb-2 border border-red-200">
135	              <span className="font-medium">Blocked:</span> {piiWarning}
136	            </div>
137	          )}
138	          {sendError && (
139	            <div className="text-sm text-red-600 bg-red-50 p-3 rounded mb-2 border border-red-200">
140	              <span className="font-medium">Error:</span> {sendError}
141	            </div>
142	          )}
143	          {fileError && (
144	            <div className="text-sm text-red-600 bg-red-50 p-3 rounded mb-2 border border-red-200">
145	              <span className="font-medium">File Error:</span> {fileError}
146	            </div>
147	          )}
148	          <div className="flex gap-2">
149	            <input
150	              type="text"
151	              value={body}
152	              onChange={(e) => { setBody(e.target.value); setPiiWarning(''); }}
153	              placeholder="Type a message..."
154	              className="flex-1 px-3 py-2 border rounded focus:outline-none focus:ring-2 focus:ring-primary-500"
155	              onKeyDown={(e) => e.key === 'Enter' && !e.shiftKey && handleSend()}
156	            />
157	            <label className="px-3 py-2 bg-gray-100 rounded cursor-pointer text-sm hover:bg-gray-200">
158	              Attach
159	              <input type="file" className="hidden" onChange={handleFileChange} />
160	            </label>
161	            <button
162	              onClick={handleSend}
163	              disabled={!body.trim() || mutation.isPending}
164	              className="px-4 py-2 bg-primary-600 text-white rounded text-sm hover:bg-primary-700 disabled:opacity-50"
165	            >
166	              Send
167	            </button>
168	          </div>
169	          {attachment && (
170	            <p className="text-xs text-gray-500 mt-1">
171	              Attached: {attachment.name} ({Math.round(attachment.size / 1024)}KB)
172	              <button onClick={() => setAttachment(null)} className="ml-2 text-red-500">Remove</button>
173	            </p>
174	          )}
175	        </div>
176	      </div>
177	    </div>
178	  );
179	}
