1	const SSN_REGEX = /\b\d{3}-?\d{2}-?\d{4}\b/;
2	const PHONE_REGEX = /\b(\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/;
3	
4	export function detectPII(text: string): { detected: boolean; types: string[] } {
5	  const types: string[] = [];
6	
7	  if (SSN_REGEX.test(text)) {
8	    types.push('SSN');
9	  }
10	  if (PHONE_REGEX.test(text)) {
11	    types.push('phone number');
12	  }
13	
14	  return { detected: types.length > 0, types };
15	}
16	
17	export function detectPIIInFile(content: string): { detected: boolean; types: string[] } {
18	  return detectPII(content);
19	}
