74	func (h *AuthHandler) Logout(c echo.Context) error {
75		userID, err := uuid.Parse(middleware.GetUserID(c))
76		if err != nil {
77			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
78		}
79	
80		cookies := h.authService.Logout(c.Request().Context(), userID)
81		for _, cookie := range cookies {
82			c.SetCookie(cookie)
83		}
84	
85		if h.auditStore != nil {
86			h.auditStore.LogEvent(c.Request().Context(), &userID, model.AuditActionLogout, "session", nil, nil, c.RealIP())
87		}
88		return c.JSON(http.StatusOK, map[string]string{"status": "ok"})
