1	package middleware
2	
3	import (
4		"strings"
5		"time"
6	
7		"github.com/labstack/echo/v4"
8		"go.uber.org/zap"
9	)
10	
11	var sensitiveFields = map[string]bool{
12		"password":      true,
13		"token":         true,
14		"authorization": true,
15		"cookie":        true,
16		"secret":        true,
17	}
18	
19	func StructuredLogger(logger *zap.Logger) echo.MiddlewareFunc {
20		return func(next echo.HandlerFunc) echo.HandlerFunc {
21			return func(c echo.Context) error {
22				start := time.Now()
23				err := next(c)
24				latency := time.Since(start)
25	
26				req := c.Request()
27				fields := []zap.Field{
28					zap.String("request_id", GetRequestID(c)),
29					zap.String("method", req.Method),
30					zap.String("path", req.URL.Path),
31					zap.Int("status", c.Response().Status),
32					zap.Duration("latency", latency),
33					zap.String("remote_ip", c.RealIP()),
34				}
35	
36				if userID, ok := c.Get("user_id").(string); ok {
37					fields = append(fields, zap.String("user_id", userID))
38				}
39	
40				if err != nil {
41					fields = append(fields, zap.Error(err))
42				}
43	
44				status := c.Response().Status
45				switch {
46				case status >= 500:
47					logger.Error("request", fields...)
48				case status >= 400:
49					logger.Warn("request", fields...)
50				default:
51					logger.Info("request", fields...)
52				}
53	
54				return err
55			}
56		}
57	}
58	
59	func RedactSensitive(key, value string) string {
60		if sensitiveFields[strings.ToLower(key)] {
61			return "[REDACTED]"
62		}
63		return value
64	}
