14	type IPRuleProvider interface {
15		GetAllIPRules() ([]model.IPRule, error)
16	}
17	
18	func IPFilter(provider IPRuleProvider, c *cache.HotCache) echo.MiddlewareFunc {
19		return func(next echo.HandlerFunc) echo.HandlerFunc {
20			return func(ctx echo.Context) error {
21				rules, err := getCachedIPRules(provider, c)
22				if err != nil {
23					// Fail closed: deny all traffic if rules cannot be loaded
24					return echo.NewHTTPError(http.StatusServiceUnavailable, dto.ErrorResponse{
25						Error: dto.ErrorDetail{
26							Code:      dto.CodeInternal,
27							Message:   "security rules unavailable",
28							RequestID: GetRequestID(ctx),
29						},
30					})
31				}
32	
33				if len(rules) == 0 {
34					return next(ctx)
35				}
36	
37				clientIP := net.ParseIP(ctx.RealIP())
38				if clientIP == nil {
39					return next(ctx)
40				}
41	
42				// Check deny rules first
43				for _, rule := range rules {
44					_, network, err := net.ParseCIDR(rule.CIDR)
45					if err != nil {
46						continue
47					}
48					if rule.Action == "deny" && network.Contains(clientIP) {
49						return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
50							Error: dto.ErrorDetail{
51								Code:      dto.CodeForbidden,
52								Message:   "IP address blocked",
53								RequestID: GetRequestID(ctx),
54							},
55						})
56					}
57				}
58	
59				// If there are allow rules, client must match at least one
60				hasAllowRules := false
61				for _, rule := range rules {
62					if rule.Action == "allow" {
63						hasAllowRules = true
64						break
65					}
66				}
67	
68				if hasAllowRules {
69					allowed := false
70					for _, rule := range rules {
71						if rule.Action != "allow" {
72							continue
73						}
74						_, network, err := net.ParseCIDR(rule.CIDR)
75						if err != nil {
76							continue
77						}
78						if network.Contains(clientIP) {
79							allowed = true
80							break
81						}
82					}
83					if !allowed {
84						return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
85							Error: dto.ErrorDetail{
86								Code:      dto.CodeForbidden,
87								Message:   "IP address not in allow list",
88								RequestID: GetRequestID(ctx),
89							},
90						})
91					}
92				}
93	
94				return next(ctx)
95			}
96		}
97	}
98	
99	func getCachedIPRules(provider IPRuleProvider, c *cache.HotCache) ([]model.IPRule, error) {
100		if cached, ok := c.Get("ip_rules"); ok {
101			return cached.([]model.IPRule), nil
102		}
103		rules, err := provider.GetAllIPRules()
104		if err != nil {
105			return nil, err
106		}
107		c.Set("ip_rules", rules, 60*time.Second)
108		return rules, nil
109	}
