13	type Config struct {
14		ListenAddr    string
15		DatabaseURL   string
16		JWTSigningKey []byte
17		AESMasterKey  []byte
18	}
19	
20	type secretsFile struct {
21		DatabaseURL   string `json:"database_url"`
22		JWTSigningKey string `json:"jwt_signing_key"`
23		AESMasterKey  string `json:"aes_master_key"`
24	}
25	
26	func Load() (*Config, error) {
27		listenAddr := os.Getenv("LISTEN_ADDR")
28		if listenAddr == "" {
29			listenAddr = ":8080"
30		}
31	
32		keyfile := os.Getenv("SECRETS_KEYFILE")
33		if keyfile != "" {
34			return loadFromKeyfile(listenAddr, keyfile)
35		}
36	
37		// Plaintext env vars only allowed in explicit development mode.
38		// When APP_ENV is empty the system assumes development for backward
39		// compatibility, but any other value (staging, production, etc.)
40		// requires an encrypted keyfile.
41		appEnv := os.Getenv("APP_ENV")
42		if appEnv != "" && appEnv != "development" {
43			return nil, fmt.Errorf("SECRETS_KEYFILE is required when APP_ENV=%s; plaintext env vars are only allowed when APP_ENV is unset or set to 'development'", appEnv)
44		}
45	
46		return loadFromEnv(listenAddr)
47	}
48	
49	func loadFromEnv(listenAddr string) (*Config, error) {
50		dbURL := os.Getenv("DATABASE_URL")
51		if dbURL == "" {
52			return nil, fmt.Errorf("DATABASE_URL is required")
53		}
54	
55		jwtKey := os.Getenv("JWT_SIGNING_KEY")
56		if jwtKey == "" {
57			return nil, fmt.Errorf("JWT_SIGNING_KEY is required")
58		}
59	
60		aesKey, err := decodeAESKey(os.Getenv("AES_MASTER_KEY"))
61		if err != nil {
62			return nil, err
63		}
64	
65		return &Config{
66			ListenAddr:    listenAddr,
67			DatabaseURL:   dbURL,
68			JWTSigningKey: []byte(jwtKey),
69			AESMasterKey:  aesKey,
70		}, nil
71	}
72	
73	func loadFromKeyfile(listenAddr, path string) (*Config, error) {
74		passphrase := os.Getenv("SECRETS_PASSPHRASE")
75		if passphrase == "" {
76			return nil, fmt.Errorf("SECRETS_PASSPHRASE is required when using SECRETS_KEYFILE")
77		}
78	
79		ciphertext, err := os.ReadFile(path)
80		if err != nil {
81			return nil, fmt.Errorf("read keyfile %s: %w", path, err)
82		}
83	
84		plaintext, err := decryptKeyfile(ciphertext, passphrase)
85		if err != nil {
86			return nil, fmt.Errorf("decrypt keyfile: %w", err)
87		}
88	
89		var secrets secretsFile
90		if err := json.Unmarshal(plaintext, &secrets); err != nil {
91			return nil, fmt.Errorf("parse keyfile JSON: %w", err)
92		}
93	
94		if secrets.DatabaseURL == "" || secrets.JWTSigningKey == "" || secrets.AESMasterKey == "" {
95			return nil, fmt.Errorf("keyfile must contain database_url, jwt_signing_key, and aes_master_key")
96		}
97	
98		aesKey, err := decodeAESKey(secrets.AESMasterKey)
99		if err != nil {
100			return nil, err
101		}
102	
103		return &Config{
104			ListenAddr:    listenAddr,
105			DatabaseURL:   secrets.DatabaseURL,
106			JWTSigningKey: []byte(secrets.JWTSigningKey),
107			AESMasterKey:  aesKey,
108		}, nil
109	}
110	
111	func decryptKeyfile(ciphertext []byte, passphrase string) ([]byte, error) {
112		key := sha256.Sum256([]byte(passphrase))
113		block, err := aes.NewCipher(key[:])
114		if err != nil {
115			return nil, err
116		}
117		gcm, err := cipher.NewGCM(block)
118		if err != nil {
119			return nil, err
120		}
121		nonceSize := gcm.NonceSize()
122		if len(ciphertext) < nonceSize {
123			return nil, fmt.Errorf("keyfile too short")
124		}
125		nonce, ct := ciphertext[:nonceSize], ciphertext[nonceSize:]
126		return gcm.Open(nil, nonce, ct, nil)
127	}
128	
129	func decodeAESKey(hexStr string) ([]byte, error) {
130		if hexStr == "" {
131			return nil, fmt.Errorf("AES_MASTER_KEY is required")
132		}
133		aesKey, err := hex.DecodeString(hexStr)
134		if err != nil {
135			return nil, fmt.Errorf("AES_MASTER_KEY must be hex-encoded: %w", err)
136		}
137		if len(aesKey) != 32 {
138			return nil, fmt.Errorf("AES_MASTER_KEY must be 32 bytes (64 hex chars), got %d bytes", len(aesKey))
139		}
140		return aesKey, nil
141	}
