90	func (s *ABTestService) GetAssignments(ctx context.Context, userID string) ([]dto.ABTestAssignment, error) {
91		tests, err := s.analyticsStore.ListRunningABTests(ctx)
92		if err != nil {
93			return nil, err
94		}
95	
96		assignments := make([]dto.ABTestAssignment, 0, len(tests))
97		for _, test := range tests {
98			variant := AssignVariant(userID, test.Name, test.TrafficPct)
99			variantName := test.ControlVariant
100			if variant == "test" {
101				variantName = test.TestVariant
102			}
103			assignments = append(assignments, dto.ABTestAssignment{
104				TestName: test.Name,
105				Variant:  variantName,
106			})
107		}
108		return assignments, nil
109	}
