1	package worker
2	
3	import (
4		"context"
5		"fmt"
6		"time"
7	
8		"github.com/ledgermint/platform/internal/store"
9		"go.uber.org/zap"
10	)
11	
12	// DeliveryFunc is the hook called to actually deliver a notification.
13	// Return nil on success or an error to mark the notification as failed.
14	// When nil (the default in production), delivery always succeeds — the
15	// platform is LAN-only, so marking as delivered *is* the delivery action.
16	type DeliveryFunc func(title, body string) error
17	
18	func NotificationRetryJob(notifStore *store.NotificationStore, logger *zap.Logger) Job {
19		return NotificationRetryJobWithDelivery(notifStore, logger, nil)
20	}
21	
22	func NotificationRetryJobWithDelivery(notifStore *store.NotificationStore, logger *zap.Logger, deliver DeliveryFunc) Job {
23		return Job{
24			Name:     "notification_retry",
25			Interval: 60 * time.Second,
26			Fn: func(ctx context.Context) error {
27				// 1. Attempt delivery for pending notifications.
28				pending, err := notifStore.GetPendingForDelivery(ctx, 100)
29				if err != nil {
30					return fmt.Errorf("get pending notifications: %w", err)
31				}
32				for _, n := range pending {
33					if deliver != nil {
34						if deliveryErr := deliver(n.RenderedTitle, n.RenderedBody); deliveryErr != nil {
35							// Delivery failed — move to "failed" so the retry path picks it up.
36							backoff := time.Duration(1<<uint(1)) * time.Minute // first retry in 2 min
37							nextRetry := time.Now().Add(backoff).Format(time.RFC3339)
38							if err := notifStore.UpdateRetryState(ctx, n.ID, "failed", 0, &nextRetry); err != nil {
39								logger.Error("mark notification failed", zap.String("id", n.ID.String()), zap.Error(err))
40							}
41							continue
42						}
43					}
44					// Delivery succeeded (or no delivery hook — LAN mode).
45					if err := notifStore.UpdateRetryState(ctx, n.ID, "delivered", 0, nil); err != nil {
46						logger.Error("deliver notification failed", zap.String("id", n.ID.String()), zap.Error(err))
47					}
48				}
49	
50				// 2. Retry failed notifications with exponential backoff.
51				failed, err := notifStore.GetFailedForRetry(ctx, 50)
52				if err != nil {
53					return fmt.Errorf("get failed notifications: %w", err)
54				}
55	
56				for _, n := range failed {
57					newRetryCount := n.RetryCount + 1
58	
59					// Attempt redelivery.
60					deliveryOK := true
61					if deliver != nil {
62						if deliveryErr := deliver(n.RenderedTitle, n.RenderedBody); deliveryErr != nil {
63							deliveryOK = false
64						}
65					}
66	
67					if deliveryOK {
68						// Retry succeeded — mark delivered.
69						if err := notifStore.UpdateRetryState(ctx, n.ID, "delivered", newRetryCount, nil); err != nil {
70							logger.Error("retry notification failed", zap.String("id", n.ID.String()), zap.Error(err))
71						}
72						continue
73					}
74	
75					// Retry still failing.
76					if newRetryCount >= n.MaxRetries {
77						// Exhausted all retries — terminal failure.
78						if err := notifStore.UpdateRetryState(ctx, n.ID, "permanently_failed", newRetryCount, nil); err != nil {
79							logger.Error("permanently fail notification", zap.String("id", n.ID.String()), zap.Error(err))
80						}
81					} else {
82						// Schedule next retry with exponential backoff.
83						backoff := time.Duration(1<<uint(newRetryCount+1)) * time.Minute
84						nextRetry := time.Now().Add(backoff).Format(time.RFC3339)
85						if err := notifStore.UpdateRetryState(ctx, n.ID, "failed", newRetryCount, &nextRetry); err != nil {
86							logger.Error("schedule notification retry", zap.String("id", n.ID.String()), zap.Error(err))
87						}
88					}
89				}
90				return nil
91			},
92		}
93	}
