14	func ABTestEvaluatorJob(analyticsStore *store.AnalyticsStore, logger *zap.Logger) Job {
15		return Job{
16			Name:     "abtest_evaluator",
17			Interval: 5 * time.Minute,
18			Fn: func(ctx context.Context) error {
19				tests, err := analyticsStore.ListRunningABTests(ctx)
20				if err != nil {
21					return err
22				}
23	
24				for _, test := range tests {
25					// Check if test has ended
26					if time.Now().After(test.EndDate) {
27						if err := analyticsStore.UpdateABTestStatus(ctx, test.ID, model.ABTestStatusCompleted); err != nil {
28							logger.Error("failed to complete A/B test", zap.String("test", test.Name), zap.Error(err))
29						}
30						continue
31					}
32	
33					// Compute conversion rates
34					controlViews, controlOrders, err := analyticsStore.GetABTestConversion(ctx, test.Name, test.ControlVariant)
35					if err != nil {
36						logger.Error("get control conversion", zap.String("test", test.Name), zap.Error(err))
37						continue
38					}
39	
40					testViews, testOrders, err := analyticsStore.GetABTestConversion(ctx, test.Name, test.TestVariant)
41					if err != nil {
42						logger.Error("get test conversion", zap.String("test", test.Name), zap.Error(err))
43						continue
44					}
45	
46					// Calculate rates
47					controlRate := float64(0)
48					if controlViews > 0 {
49						controlRate = float64(controlOrders) / float64(controlViews)
50					}
51					testRate := float64(0)
52					if testViews > 0 {
53						testRate = float64(testOrders) / float64(testViews)
54					}
55	
56					// Save results
57					for _, r := range []struct {
58						variant string
59						views   int64
60						orders  int64
61						rate    float64
62					}{
63						{test.ControlVariant, controlViews, controlOrders, controlRate},
64						{test.TestVariant, testViews, testOrders, testRate},
65					} {
66						result := &model.ABTestResult{
67							ABTestID:       test.ID,
68							Variant:        r.variant,
69							Views:          r.views,
70							Orders:         r.orders,
71							ConversionRate: r.rate,
72						}
73						if err := analyticsStore.SaveABTestResult(ctx, result); err != nil {
74							logger.Error("save A/B result", zap.String("test", test.Name), zap.Error(err))
75						}
76					}
77	
78					// Auto-rollback check with relative drop and minimum sample size
79					if controlViews < minSampleSize || testViews < minSampleSize {
80						continue // Not enough data
81					}
82	
83					if controlRate > 0 {
84						relativeDrop := (controlRate - testRate) / controlRate * 100
85						if relativeDrop > float64(test.RollbackThresholdPct) {
86							logger.Warn("A/B test auto-rollback triggered",
87								zap.String("test", test.Name),
88								zap.Float64("control_rate", controlRate),
89								zap.Float64("test_rate", testRate),
90								zap.Float64("relative_drop_pct", relativeDrop),
91								zap.Int("threshold_pct", test.RollbackThresholdPct))
92	
93							if err := analyticsStore.UpdateABTestStatus(ctx, test.ID, model.ABTestStatusRolledBack); err != nil {
94								logger.Error("auto-rollback failed", zap.String("test", test.Name), zap.Error(err))
95							}
96						}
97					}
98				}
99				return nil
100			},
101		}
102	}
