15	CREATE INDEX idx_audit_logs_resource ON audit_logs(resource_type, resource_id, created_at DESC);
16	
17	-- Append-only protection: prevent updates and deletes on audit_logs.
18	CREATE OR REPLACE FUNCTION prevent_audit_log_mutation() RETURNS TRIGGER AS $$
19	BEGIN
20	    RAISE EXCEPTION 'audit_logs is append-only: updates and deletes are not allowed';
21	    RETURN NULL;
22	END;
23	$$ LANGUAGE plpgsql;
24	
