72		cacheKey := "collectible:" + id.String()
73		if cached, ok := s.cache.Get(cacheKey); ok {
74			c := cached.(*model.Collectible)
75			if c.Status == "hidden" && !hasAdminOrCompliance(viewerRoles) {
76				return nil, dto.ErrNotFound
