243	// resolveABVariant builds a comma-separated ab_variant tag for all running tests.
244	// Returns "" if there are no running tests or the user is nil.
245	func resolveABVariant(analyticsStore *store.AnalyticsStore, userID *uuid.UUID) string {
246		if userID == nil || analyticsStore == nil {
247			return ""
248		}
249		tests, _ := analyticsStore.ListRunningABTests(context.Background())
250		if len(tests) == 0 {
251			return ""
252		}
253		parts := make([]string, 0, len(tests))
254		for _, t := range tests {
255			v := AssignVariant(userID.String(), t.Name, t.TrafficPct)
256			variantName := t.ControlVariant
257			if v == "test" {
258				variantName = t.TestVariant
259			}
260			parts = append(parts, t.Name+":"+variantName)
261		}
262		return strings.Join(parts, ",")
263	}
