102	// GetByID with object-level authorization: only buyer or seller of the order can view it.
103	func (s *OrderService) GetByID(ctx context.Context, id uuid.UUID, actorID uuid.UUID) (*model.Order, error) {
104		order, err := s.orderStore.GetByID(ctx, id)
105		if err != nil {
106			return nil, err
107		}
108		if order == nil {
109			return nil, dto.ErrNotFound
110		}
111		if order.BuyerID != actorID && order.SellerID != actorID {
112			return nil, dto.ErrForbidden
113		}
114		return order, nil
115	}
116	
117	// TransitionStatus with object-level authorization.
118	// Confirm/Process/Complete: only the seller of THIS order.
119	// Cancel: only the buyer or seller of THIS order.
120	func (s *OrderService) TransitionStatus(ctx context.Context, orderID uuid.UUID, targetStatus model.OrderStatus, actorID uuid.UUID, reason string) (*model.Order, error) {
121		order, err := s.orderStore.GetByID(ctx, orderID)
122		if err != nil {
123			return nil, err
124		}
125		if order == nil {
126			return nil, dto.ErrNotFound
127		}
128	
129		// Object-level authorization
130		switch targetStatus {
131		case model.OrderStatusConfirmed, model.OrderStatusProcessing, model.OrderStatusCompleted:
132			if order.SellerID != actorID {
133				return nil, fmt.Errorf("%w: only the seller of this order can perform this action", dto.ErrForbidden)
134			}
135		case model.OrderStatusCancelled:
136			if order.BuyerID != actorID && order.SellerID != actorID {
137				return nil, fmt.Errorf("%w: only the buyer or seller of this order can cancel it", dto.ErrForbidden)
138			}
139		}
140	
141		if !order.Status.CanTransitionTo(targetStatus) {
142			return nil, fmt.Errorf("%w: cannot transition from %s to %s", dto.ErrInvalidTransition, order.Status, targetStatus)
143		}
144	
145		if targetStatus == model.OrderStatusCancelled {
146			if err := s.orderStore.Cancel(ctx, orderID, reason, actorID); err != nil {
147				return nil, fmt.Errorf("cancel order: %w", err)
148			}
149			s.emitEvent(ctx, &actorID, "order_cancelled", &order.CollectibleID)
150		} else {
151			if err := s.orderStore.UpdateStatus(ctx, orderID, targetStatus); err != nil {
152				return nil, fmt.Errorf("update status: %w", err)
153			}
154		}
155	
156		transition := &model.OrderStateTransition{
157			OrderID:    orderID,
158			FromStatus: order.Status,
159			ToStatus:   targetStatus,
160			ActorID:    actorID,
161			Reason:     reason,
162		}
163		if err := s.orderStore.RecordTransition(ctx, transition); err != nil {
164			return nil, fmt.Errorf("record transition: %w", err)
165		}
166	
167		s.sendOrderNotification(ctx, order, targetStatus, reason)
168	
169		order.Status = targetStatus
170		return order, nil
171	}
