{"file_path": "/Users/macbookpro/Projects/eaglepoint/w1t21/repo/unit_tests/test_abtest_registry.py", "content": """"Unit tests for the A/B test experiment-to-component registry.

Mirrors the validation logic in backend/internal/service/abtest_registry.go.
"""
import unittest


# Replicate the registry from abtest_registry.go
EXPERIMENT_REGISTRY = {
    "catalog_layout": {
        "description": "Controls the collectible catalog grid layout (CatalogPage.tsx)",
        "allowed_variants": {"grid", "list"},
    },
}


def validate_experiment(name: str, control_variant: str, test_variant: str) -> str:
    """Return empty string on success, error message on failure."""
    if name not in EXPERIMENT_REGISTRY:
        allowed = ", ".join(sorted(EXPERIMENT_REGISTRY.keys())) or "(none)"
        return f"unknown experiment name '{name}'; registered experiments: {allowed}"

    comp = EXPERIMENT_REGISTRY[name]
    if control_variant not in comp["allowed_variants"]:
        allowed = ", ".join(sorted(comp["allowed_variants"]))
        return f"control variant '{control_variant}' is not registered for experiment '{name}'; allowed: {allowed}"
    if test_variant not in comp["allowed_variants"]:
        allowed = ", ".join(sorted(comp["allowed_variants"]))
        return f"test variant '{test_variant}' is not registered for experiment '{name}'; allowed: {allowed}"
    if control_variant == test_variant:
        return "control and test variants must be different"
    return ""


class TestRegisteredExperiment(unittest.TestCase):
    """Valid experiment + variant combinations."""

    def test_catalog_layout_grid_list(self):
        self.assertEqual(validate_experiment("catalog_layout", "grid", "list"), "")

    def test_catalog_layout_list_grid(self):
        self.assertEqual(validate_experiment("catalog_layout", "list", "grid"), "")


class TestUnregisteredExperiment(unittest.TestCase):
    """Experiment names not in the registry."""

    def test_unknown_name_rejected(self):
        msg = validate_experiment("checkout_flow", "a", "b")
        self.assertIn("unknown experiment", msg)
        self.assertIn("catalog_layout", msg)

    def test_empty_name_rejected(self):
        msg = validate_experiment("", "grid", "list")
        self.assertIn("unknown experiment", msg)


class TestInvalidVariants(unittest.TestCase):
    """Registered experiment but unregistered variant names."""

    def test_bad_control_variant(self):
        msg = validate_experiment("catalog_layout", "carousel", "list")
        self.assertIn("control variant", msg)
        self.assertIn("not registered", msg)

    def test_bad_test_variant(self):
        msg = validate_experiment("catalog_layout", "grid", "carousel")
        self.assertIn("test variant", msg)
        self.assertIn("not registered", msg)

    def test_both_variants_bad(self):
        msg = validate_experiment("catalog_layout", "a", "b")
        # Should fail on control variant first
        self.assertIn("control variant", msg)

    def test_same_variants_rejected(self):
        msg = validate_experiment("catalog_layout", "grid", "grid")
        self.assertIn("must be different", msg)


class TestRegistryCompleteness(unittest.TestCase):
    """Ensure registry entries have at least two variants."""

    def test_all_components_have_two_variants(self):
        for name, comp in EXPERIMENT_REGISTRY.items():
            self.assertGreaterEqual(
                len(comp["allowed_variants"]), 2,
                f"Experiment '{name}' must have at least 2 variants",
            )

    def test_registry_not_empty(self):
        self.assertGreater(len(EXPERIMENT_REGISTRY), 0)

    def test_catalog_layout_registered(self):
        self.assertIn("catalog_layout", EXPERIMENT_REGISTRY)


class TestNotificationTemplateScope(unittest.TestCase):
    """Verify that only supported notification template slugs are declared.

    This mirrors the cleanup in migration 013 — only the 4 order-lifecycle
    templates should remain.
    """

    SUPPORTED_SLUGS = {
        "order_confirmed",
        "order_processing",
        "order_completed",
        "order_cancelled",
    }
    REMOVED_SLUGS = {
        "refund_approved",
        "arbitration_opened",
        "review_posted",
    }

    def test_supported_slugs_complete(self):
        self.assertEqual(len(self.SUPPORTED_SLUGS), 4)

    def test_removed_slugs_not_in_supported(self):
        self.assertTrue(self.SUPPORTED_SLUGS.isdisjoint(self.REMOVED_SLUGS))


if __name__ == "__main__":
    unittest.main()
"}

