46	func (h *MessageHandler) Send(c echo.Context) error {
47		orderID, err := uuid.Parse(c.Param("orderId"))
48		if err != nil {
49			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
50		}
51	
52		userID, err := uuid.Parse(middleware.GetUserID(c))
53		if err != nil {
54			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
55		}
56	
57		body := c.FormValue("body")
58		if body == "" {
59			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, "message body is required")
60		}
61	
62		// Server-side PII detection
63		if detected, piiTypes := service.DetectPII(body); detected {
64			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, service.PIIErrorMessage(piiTypes))
65		}
66	
67		var attachmentPath, attachmentMime string
68		var attachmentSize int
69	
70		file, err := c.FormFile("attachment")
71		if err == nil {
72			// Server-side 10MB enforcement
73			if file.Size > service.MaxAttachmentSize {
74				return errorResponse(c, http.StatusRequestEntityTooLarge, dto.CodeAttachmentTooLarge, "attachment exceeds 10MB limit")
75			}
76	
77			src, err := file.Open()
78			if err != nil {
79				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to read attachment")
80			}
81			defer src.Close()
82	
83			mime := file.Header.Get("Content-Type")
84			ext := filepath.Ext(file.Filename)
85	
86			// PII scan for text-based attachments before saving
87			var buf *bytes.Buffer
88			if isTextAttachment(mime, ext) {
89				buf = &bytes.Buffer{}
90				if _, err := io.Copy(buf, src); err != nil {
91					return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to read attachment")
92				}
93				if detected, piiTypes := service.DetectPII(buf.String()); detected {
94					c.Logger().Warn("attachment PII blocked for order ", orderID.String())
95					return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation,
96						"attachment blocked: contains sensitive personal information ("+strings.Join(piiTypes, ", ")+")")
97				}
98			}
99	
100			dir := filepath.Join(h.uploadDir, orderID.String())
101			if err := os.MkdirAll(dir, 0o755); err != nil {
102				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to create upload directory")
103			}
104	
105			filename := uuid.New().String() + ext
106			dstPath := filepath.Join(dir, filename)
107	
108			dst, err := os.Create(dstPath)
109			if err != nil {
110				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to save attachment")
111			}
112			defer dst.Close()
113	
114			if buf != nil {
115				if _, err := io.Copy(dst, buf); err != nil {
116					return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to write attachment")
117				}
118			} else {
119				if _, err := io.Copy(dst, src); err != nil {
120					return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to write attachment")
121				}
122			}
123	
124			attachmentPath = dstPath
125			attachmentSize = int(file.Size)
126			attachmentMime = mime
127		}
128	
129		msg, err := h.messageService.Send(c.Request().Context(), orderID, userID, body,
130			attachmentPath, attachmentSize, attachmentMime)
131		if err != nil {
132			return mapError(c, err)
133		}
134		return c.JSON(http.StatusCreated, msg)
135	}
136	
137	// isTextAttachment returns true for file types whose content should be scanned as text.
138	func isTextAttachment(mime string, ext string) bool {
139		if strings.HasPrefix(mime, "text/") {
140			return true
141		}
142		ext = strings.ToLower(ext)
143		return ext == ".csv" || ext == ".txt"
144	}
