17	)
18	
19	const (
20		// Rolling-window abuse thresholds
21		maxUserFailures = 5
22		maxIPFailures   = 20
23		failureWindow   = 15 * time.Minute
24		lockoutDuration = 30 * time.Minute
25	)
26	
27	type AuthService struct {
28		userStore  *store.UserStore
29		signingKey []byte
30	}
31	
32	func NewAuthService(userStore *store.UserStore, signingKey []byte) *AuthService {
33		return &AuthService{userStore: userStore, signingKey: signingKey}
34	}
35	
36	func (s *AuthService) Login(ctx context.Context, req dto.LoginRequest, clientIP string) (*dto.AuthResponse, []*http.Cookie, error) {
37		windowStart := time.Now().Add(-failureWindow)
38	
39		// IP-based rolling-window check — blocks brute force across usernames
40		ipCount, err := s.userStore.CountRecentFailuresByIP(ctx, clientIP, windowStart)
41		if err != nil {
42			return nil, nil, fmt.Errorf("count IP failures: %w", err)
43		}
44		if ipCount >= maxIPFailures {
45			return nil, nil, dto.ErrAccountLocked
46		}
47	
48		user, err := s.userStore.GetByUsername(ctx, req.Username)
49		if err != nil {
50			return nil, nil, fmt.Errorf("lookup user: %w", err)
51		}
52		if user == nil {
53			// Record attempt against IP even for unknown usernames
54			_ = s.userStore.RecordFailedAttempt(ctx, nil, clientIP)
55			return nil, nil, dto.ErrInvalidCredentials
56		}
57	
58		// User-level lockout check with expiry
59		if user.IsLocked {
60			if user.LockedUntil != nil && time.Now().Before(*user.LockedUntil) {
61				return nil, nil, dto.ErrAccountLocked
62			}
63			// Lock expired — release it
64			if err := s.userStore.UnlockAccount(ctx, user.ID); err != nil {
65				return nil, nil, fmt.Errorf("unlock account: %w", err)
66			}
67		}
68	
69		if !crypto.CheckPassword(user.PasswordHash, req.Password) {
70			// Record the failed attempt
71			if err := s.userStore.RecordFailedAttempt(ctx, &user.ID, clientIP); err != nil {
72				return nil, nil, fmt.Errorf("record failed attempt: %w", err)
73			}
74	
75			// Evaluate user threshold in the rolling window
76			userCount, err := s.userStore.CountRecentFailuresByUser(ctx, user.ID, windowStart)
77			if err != nil {
78				return nil, nil, fmt.Errorf("count user failures: %w", err)
79			}
80			if userCount >= maxUserFailures {
81				lockUntil := time.Now().Add(lockoutDuration).Format(time.RFC3339)
82				if err := s.userStore.LockAccount(ctx, user.ID, lockUntil); err != nil {
83					return nil, nil, fmt.Errorf("lock account: %w", err)
84				}
85			}
86	
87			return nil, nil, dto.ErrInvalidCredentials
88		}
89	
90		// Successful login — clear rolling-window entries and legacy counter
91		if err := s.userStore.ClearFailedAttempts(ctx, user.ID); err != nil {
92			return nil, nil, fmt.Errorf("clear failed attempts: %w", err)
93		}
94		if err := s.userStore.ResetFailedLogin(ctx, user.ID); err != nil {
95			return nil, nil, fmt.Errorf("reset failed login: %w", err)
96		}
97	
98		userRoles, err := s.userStore.GetUserRoles(ctx, user.ID)
99		if err != nil {
100			return nil, nil, fmt.Errorf("get roles: %w", err)
101		}
102		roleNames := make([]string, len(userRoles))
103		for i, r := range userRoles {
104			roleNames[i] = r.RoleName
105		}
106	
107		accessToken, err := s.generateAccessToken(user.ID.String(), roleNames)
108		if err != nil {
109			return nil, nil, fmt.Errorf("generate access token: %w", err)
110		}
111	
112		refreshTokenStr := uuid.New().String()
113		familyID := uuid.New()
114		tokenHash := sha256.Sum256([]byte(refreshTokenStr))
115	
116		rt := &model.RefreshToken{
117			ID:        uuid.New(),
118			UserID:    user.ID,
119			TokenHash: tokenHash[:],
120			FamilyID:  familyID,
121			ExpiresAt: time.Now().Add(7 * 24 * time.Hour),
122		}
123		if err := s.userStore.CreateRefreshToken(ctx, rt); err != nil {
124			return nil, nil, fmt.Errorf("create refresh token: %w", err)
125		}
126	
127		csrfToken, err := middleware.GenerateCSRFToken()
128		if err != nil {
129			return nil, nil, fmt.Errorf("generate CSRF token: %w", err)
130		}
131	
132		cookies := []*http.Cookie{
133			{
134				Name: "access_token", Value: accessToken, Path: "/",
135				HttpOnly: true, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 900,
136			},
137			{
138				Name: "refresh_token", Value: refreshTokenStr, Path: "/api/auth",
139				HttpOnly: true, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 604800,
140			},
141			{
142				Name: "csrf_token", Value: csrfToken, Path: "/",
143				HttpOnly: false, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 604800,
144			},
145		}
146	
147		resp := &dto.AuthResponse{
148			User: dto.UserResponse{
149				ID: user.ID, Username: user.Username, DisplayName: user.DisplayName,
150				IsLocked: user.IsLocked, CreatedAt: user.CreatedAt, UpdatedAt: user.UpdatedAt,
151			},
152			Roles: roleNames,
153		}
154		return resp, cookies, nil
155	}
156	
157	func (s *AuthService) Refresh(ctx context.Context, refreshTokenStr string) ([]*http.Cookie, error) {
158		tokenHash := sha256.Sum256([]byte(refreshTokenStr))
159		rt, err := s.userStore.GetRefreshTokenByHash(ctx, tokenHash[:])
160		if err != nil {
161			return nil, fmt.Errorf("lookup refresh token: %w", err)
162		}
163		if rt == nil {
164			return nil, dto.ErrUnauthorized
165		}
166	
167		if rt.RevokedAt != nil {
168			_ = s.userStore.RevokeRefreshTokenFamily(ctx, rt.FamilyID)
169			return nil, dto.ErrUnauthorized
170		}
171		if time.Now().After(rt.ExpiresAt) {
172			return nil, dto.ErrUnauthorized
173		}
174	
175		if err := s.userStore.RevokeRefreshToken(ctx, rt.ID); err != nil {
176			return nil, fmt.Errorf("revoke token: %w", err)
177		}
178	
179		user, err := s.userStore.GetByID(ctx, rt.UserID)
180		if err != nil || user == nil {
181			return nil, dto.ErrUnauthorized
182		}
183	
184		userRoles, err := s.userStore.GetUserRoles(ctx, user.ID)
185		if err != nil {
186			return nil, fmt.Errorf("get roles: %w", err)
187		}
188		roleNames := make([]string, len(userRoles))
189		for i, r := range userRoles {
190			roleNames[i] = r.RoleName
191		}
192	
193		accessToken, err := s.generateAccessToken(user.ID.String(), roleNames)
194		if err != nil {
195			return nil, fmt.Errorf("generate access token: %w", err)
196		}
197	
198		newRefreshStr := uuid.New().String()
199		newHash := sha256.Sum256([]byte(newRefreshStr))
200		newRT := &model.RefreshToken{
201			ID: uuid.New(), UserID: rt.UserID, TokenHash: newHash[:],
202			FamilyID: rt.FamilyID, ExpiresAt: time.Now().Add(7 * 24 * time.Hour),
203		}
204		if err := s.userStore.CreateRefreshToken(ctx, newRT); err != nil {
205			return nil, fmt.Errorf("create refresh token: %w", err)
206		}
207	
208		csrfToken, err := middleware.GenerateCSRFToken()
209		if err != nil {
210			return nil, fmt.Errorf("generate CSRF token: %w", err)
211		}
212	
213		cookies := []*http.Cookie{
214			{Name: "access_token", Value: accessToken, Path: "/", HttpOnly: true, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 900},
215			{Name: "refresh_token", Value: newRefreshStr, Path: "/api/auth", HttpOnly: true, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 604800},
216			{Name: "csrf_token", Value: csrfToken, Path: "/", HttpOnly: false, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 604800},
217		}
218		return cookies, nil
219	}
220	
221	func (s *AuthService) Logout(ctx context.Context, userID uuid.UUID) []*http.Cookie {
222		_ = s.userStore.RevokeAllUserTokens(ctx, userID)
223		return []*http.Cookie{
224			{Name: "access_token", Value: "", Path: "/", MaxAge: -1, HttpOnly: true},
225			{Name: "refresh_token", Value: "", Path: "/api/auth", MaxAge: -1, HttpOnly: true},
226			{Name: "csrf_token", Value: "", Path: "/", MaxAge: -1},
227		}
228	}
229	
230	func (s *AuthService) generateAccessToken(userID string, roles []string) (string, error) {
231		claims := &middleware.UserClaims{
232			UserID: userID,
233			Roles:  roles,
234			RegisteredClaims: jwt.RegisteredClaims{
235				ExpiresAt: jwt.NewNumericDate(time.Now().Add(15 * time.Minute)),
236				IssuedAt:  jwt.NewNumericDate(time.Now()),
237				Issuer:    "ledgermint",
238			},
239		}
240		token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
241		return token.SignedString(s.signingKey)
242	}
