import { describe, it, expect } from 'vitest';

const ERROR_CODES = {
  ERR_NOT_FOUND:           404,
  ERR_FORBIDDEN:           403,
  ERR_UNAUTHORIZED:        401,
  ERR_CONFLICT:            409,
  ERR_RATE_LIMITED:        429,
  ERR_VALIDATION:          422,
  ERR_ACCOUNT_LOCKED:      423,
  ERR_INVALID_CREDENTIALS: 401,
  ERR_ATTACHMENT_TOO_LARGE:413,
  ERR_ORDER_DUPLICATE:     409,
  ERR_INVALID_TRANSITION:  422,
  ERR_OVERSOLD:            409,
  ERR_INTERNAL:            500,
};

const VALID_HTTP = new Set([400, 401, 403, 404, 409, 413, 422, 423, 429, 500]);

describe('Error Code → HTTP Status Mapping', () => {
  it.each(Object.entries(ERROR_CODES))('%s → %i', (code, status) => {
    expect(VALID_HTTP.has(status)).toBe(true);
  });

  it('ERR_NOT_FOUND → 404',           () => expect(ERROR_CODES.ERR_NOT_FOUND).toBe(404));
  it('ERR_FORBIDDEN → 403',           () => expect(ERROR_CODES.ERR_FORBIDDEN).toBe(403));
  it('ERR_UNAUTHORIZED → 401',        () => expect(ERROR_CODES.ERR_UNAUTHORIZED).toBe(401));
  it('ERR_ACCOUNT_LOCKED → 423',      () => expect(ERROR_CODES.ERR_ACCOUNT_LOCKED).toBe(423));
  it('ERR_INVALID_CREDENTIALS → 401', () => expect(ERROR_CODES.ERR_INVALID_CREDENTIALS).toBe(401));
  it('ERR_ATTACHMENT_TOO_LARGE → 413', () => expect(ERROR_CODES.ERR_ATTACHMENT_TOO_LARGE).toBe(413));
  it('ERR_OVERSOLD → 409',            () => expect(ERROR_CODES.ERR_OVERSOLD).toBe(409));
  it('ERR_INTERNAL → 500',            () => expect(ERROR_CODES.ERR_INTERNAL).toBe(500));
});

describe('Error Response Structure', () => {
  it('envelope has error.code, error.message, error.request_id', () => {
    const sample = { error: { code: 'ERR_NOT_FOUND', message: 'not found', request_id: 'abc-123' } };
    expect(sample.error).toHaveProperty('code');
    expect(sample.error).toHaveProperty('message');
    expect(sample.error).toHaveProperty('request_id');
  });

  it('all codes start with ERR_ and are uppercase', () => {
    for (const code of Object.keys(ERROR_CODES)) {
      expect(code).toMatch(/^ERR_/);
      expect(code).toBe(code.toUpperCase());
    }
  });
});

describe('Role Authorization Rules', () => {
  const ROUTE_ROLES = {
    '/api/users':                   ['administrator'],
    '/api/collectibles/mine':       ['seller'],
    '/api/collectibles (POST)':     ['seller'],
    '/api/collectibles/:id/hide':   ['administrator'],
    '/api/collectibles/:id/publish':['administrator'],
    '/api/orders (POST)':           ['buyer'],
    '/api/orders/:id/confirm':      ['seller'],
    '/api/orders/:id/process':      ['seller'],
    '/api/orders/:id/complete':     ['seller'],
    '/api/orders/:id/fulfillment':  ['seller'],
    '/api/analytics':               ['administrator', 'compliance_analyst'],
    '/api/ab-tests':                ['administrator'],
    '/api/admin/ip-rules':          ['administrator'],
    '/api/admin/anomalies':         ['administrator', 'compliance_analyst'],
  };

  it('user management requires admin',        () => expect(ROUTE_ROLES['/api/users']).toEqual(['administrator']));
  it('listing creation requires seller',      () => expect(ROUTE_ROLES['/api/collectibles (POST)']).toEqual(['seller']));
  it('order creation requires buyer',         () => expect(ROUTE_ROLES['/api/orders (POST)']).toEqual(['buyer']));
  it('order confirm requires seller',         () => expect(ROUTE_ROLES['/api/orders/:id/confirm']).toEqual(['seller']));
  it('analytics allows admin and compliance', () => {
    expect(ROUTE_ROLES['/api/analytics']).toContain('administrator');
    expect(ROUTE_ROLES['/api/analytics']).toContain('compliance_analyst');
  });
  it('A/B tests admin only',    () => expect(ROUTE_ROLES['/api/ab-tests']).toEqual(['administrator']));
  it('moderation requires admin', () => {
    expect(ROUTE_ROLES['/api/collectibles/:id/hide']).toEqual(['administrator']);
    expect(ROUTE_ROLES['/api/collectibles/:id/publish']).toEqual(['administrator']);
  });
});
"}

