import { describe, it, expect } from 'vitest';

const RULES = {
  username:              { min: 3, max: 100, required: true },
  password:              { min: 8, max: 128, required: true },
  display_name:          { max: 200, required: true },
  email:                 { pattern: /^[^@]+@[^@]+\.[^@]+$/, required: false },
  title:                 { max: 300, required: true },
  description:           { max: 5000, required: false },
  currency:              { exactLen: 3, required: false },
  contract_address:      { max: 42, required: false },
  cancel_reason:         { max: 500, required: true },
  hide_reason:           { max: 500, required: true },
  message_body:          { max: 5000, required: true },
  role_name:             { allowed: ['buyer', 'seller', 'administrator', 'compliance_analyst'], required: true },
  ip_action:             { allowed: ['allow', 'deny'], required: true },
  traffic_pct:           { min: 1, max: 100, required: true },
  rollback_threshold_pct:{ min: 1, max: 100, required: true },
  price_cents:           { min: 1, required: true },
};

function validateLength(value, rules) {
  if (rules.required && !value) return false;
  if (!value && !rules.required) return true;
  if (rules.min !== undefined && value.length < rules.min) return false;
  if (rules.max !== undefined && value.length > rules.max) return false;
  if (rules.exactLen !== undefined && value.length !== rules.exactLen) return false;
  if (rules.pattern && !rules.pattern.test(value)) return false;
  if (rules.allowed && !rules.allowed.includes(value)) return false;
  return true;
}

function validateNumeric(value, rules) {
  if (rules.required && value == null) return false;
  if (value == null && !rules.required) return true;
  if (rules.min !== undefined && value < rules.min) return false;
  if (rules.max !== undefined && value > rules.max) return false;
  return true;
}

describe('Username', () => {
  it('valid',          () => expect(validateLength('admin', RULES.username)).toBe(true));
  it('min boundary ok',() => expect(validateLength('abc', RULES.username)).toBe(true));
  it('below min',      () => expect(validateLength('ab', RULES.username)).toBe(false));
  it('max boundary ok',() => expect(validateLength('a'.repeat(100), RULES.username)).toBe(true));
  it('above max',      () => expect(validateLength('a'.repeat(101), RULES.username)).toBe(false));
  it('required',       () => expect(validateLength('', RULES.username)).toBe(false));
});

describe('Password', () => {
  it('valid',          () => expect(validateLength('password123', RULES.password)).toBe(true));
  it('min boundary',   () => expect(validateLength('12345678', RULES.password)).toBe(true));
  it('below min',      () => expect(validateLength('1234567', RULES.password)).toBe(false));
  it('max boundary',   () => expect(validateLength('a'.repeat(128), RULES.password)).toBe(true));
  it('above max',      () => expect(validateLength('a'.repeat(129), RULES.password)).toBe(false));
});

describe('Email', () => {
  it('valid',          () => expect(validateLength('user@example.com', RULES.email)).toBe(true));
  it('no @',           () => expect(validateLength('userexample.com', RULES.email)).toBe(false));
  it('optional empty', () => expect(validateLength('', RULES.email)).toBe(true));
});

describe('Collectible Fields', () => {
  it('title required',         () => expect(validateLength('', RULES.title)).toBe(false));
  it('title max',              () => expect(validateLength('a'.repeat(301), RULES.title)).toBe(false));
  it('description optional',   () => expect(validateLength('', RULES.description)).toBe(true));
