  it('permanently_failed is terminal',       () => expect(TRANSITIONS.permanently_failed.size).toBe(0));

  it('max retries default 3', () => expect(3).toBe(3));
  it('exponential backoff', () => {
    expect(1 << 1).toBe(2);
    expect(1 << 2).toBe(4);
    expect(1 << 3).toBe(8);
  });
});

// A/B assignment
describe('A/B Variant Assignment', () => {
  it('deterministic',            () => expect(assignVariant('u1', 't1', 50)).toBe(assignVariant('u1', 't1', 50)));
